/// <summary>
///
/// </summary>
/// <param name="args"></param>
[PostHandlerFor(tableStr(InventTable), tableMethodStr(InventTable, insert))]
public static void InventTable_Post_insert(XppPrePostArgs args)
{
    ETG_Parameters  etgNotes = ETG_Parameters::find();
    ETGTradingNotes tradingNotes;
    InventTable     inventTable = args.getThis();

    select * from tradingNotes
            where tradingNotes.ItemId == inventTable.ItemId;

    if (!tradingNotes)
    {
        tradingNotes.clear();
        if (eTgnotes.Header)
        {
            tradingNotes.EnumNotes   = ETGNote::Header;
            tradingNotes.Description = eTgnotes.Header;
            tradingNotes.ItemId      = inventTable.ItemId;
            tradingNotes.PrintNotesInContract = NoYes::Yes;
            tradingNotes.insert();
        }
        if (eTgnotes.Title)
        {
            tradingNotes.EnumNotes   = ETGNote::Title;
            tradingNotes.Description = eTgnotes.Title;
            tradingNotes.ItemId      = inventTable.ItemId;
            tradingNotes.PrintNotesInContract = NoYes::Yes;
            tradingNotes.insert();
        }
        if (eTgnotes.Acceptance)
        {
            tradingNotes.EnumNotes   = ETGNote::Acceptance;
            tradingNotes.Description = eTgnotes.Acceptance;
            tradingNotes.ItemId      = inventTable.ItemId;
            tradingNotes.PrintNotesInContract = NoYes::Yes;
            tradingNotes.insert();
        }
        if (eTgnotes.Arbitration)
        {
            tradingNotes.EnumNotes   = ETGNote::Arbitration;
            tradingNotes.Description = eTgnotes.Arbitration;
            tradingNotes.ItemId      = inventTable.ItemId;
            tradingNotes.PrintNotesInContract = NoYes::Yes;
            tradingNotes.insert();
        }
        if (eTgnotes.Broker)
        {
            tradingNotes.EnumNotes   = ETGNote::Broker;
            tradingNotes.Description = eTgnotes.Broker;
            tradingNotes.ItemId      = inventTable.ItemId;
            tradingNotes.PrintNotesInContract = NoYes::Yes;
            tradingNotes.insert();
        }
        if (eTgnotes.Confidentiality)
        {
            tradingNotes.EnumNotes   = ETGNote::Confidentiality;
            tradingNotes.Description = eTgnotes.Confidentiality;
            tradingNotes.ItemId      = inventTable.ItemId;
            tradingNotes.PrintNotesInContract = NoYes::Yes;
            tradingNotes.insert();
        }
        if (eTgnotes.Delivery)
        {
            tradingNotes.EnumNotes   = ETGNote::Delivery;
            tradingNotes.Description = eTgnotes.Delivery;
            tradingNotes.ItemId      = inventTable.ItemId;
            tradingNotes.PrintNotesInContract = NoYes::Yes;
            tradingNotes.insert();
        }
        if (eTgnotes.Documents)
        {
            tradingNotes.EnumNotes   = ETGNote::Documents;
            tradingNotes.Description = eTgnotes.Documents;
            tradingNotes.ItemId      = inventTable.ItemId;
            tradingNotes.PrintNotesInContract = NoYes::Yes;
            tradingNotes.insert();
        }
        if (eTgnotes.ForceMajeure)
        {
            tradingNotes.EnumNotes   = ETGNote::ForceMajeure;
            tradingNotes.Description = eTgnotes.ForceMajeure;
            tradingNotes.ItemId      = inventTable.ItemId;
            tradingNotes.insert();
        }
        if (eTgnotes.Insurance)
        {
            tradingNotes.EnumNotes   = ETGNote::Insurance;
            tradingNotes.Description = eTgnotes.Insurance;
            tradingNotes.ItemId      = inventTable.ItemId;
            tradingNotes.PrintNotesInContract = NoYes::Yes;
            tradingNotes.insert();
        }
        if (eTgnotes.LandedWeightSupervision)
        {
            tradingNotes.EnumNotes   = ETGNote::LandedWeightSupervision;
            tradingNotes.Description = eTgnotes.LandedWeightSupervision;
            tradingNotes.ItemId      = inventTable.ItemId;
            tradingNotes.PrintNotesInContract = NoYes::Yes;
            tradingNotes.insert();
        }
        if (eTgnotes.LicenseTaxation)
        {
            tradingNotes.EnumNotes   = ETGNote::LicenseTaxation;
            tradingNotes.Description = eTgnotes.LicenseTaxation;
            tradingNotes.ItemId               = inventTable.ItemId;
            tradingNotes.PrintNotesInContract = NoYes::Yes;
            tradingNotes.PrintNotesInContract = NoYes::Yes;
            tradingNotes.insert();
        }
        if (eTgnotes.NoObjection)
        {
            tradingNotes.EnumNotes   = ETGNote::NoObjection;
            tradingNotes.Description = eTgnotes.NoObjection;
            tradingNotes.ItemId      = inventTable.ItemId;
            tradingNotes.PrintNotesInContract = NoYes::Yes;
            tradingNotes.insert();
        }
        if (eTgnotes.OtherConditions)
        {
            tradingNotes.EnumNotes   = ETGNote::OtherConditions;
            tradingNotes.Description = eTgnotes.OtherConditions;
            tradingNotes.ItemId      = inventTable.ItemId;
            tradingNotes.PrintNotesInContract = NoYes::Yes;
            tradingNotes.insert();
        }
        if (eTgnotes.WeightQualityAssesment)
        {
            tradingNotes.EnumNotes   = ETGNote::WeightQualityAssesment;
            tradingNotes.Description = eTgnotes.WeightQualityAssesment;
            tradingNotes.ItemId      = inventTable.ItemId;
            tradingNotes.PrintNotesInContract = NoYes::Yes;
            tradingNotes.insert();
        }
        if (eTgnotes.WeightSpecs)
        {
            tradingNotes.EnumNotes   = ETGNote::WeightSpecs;
            tradingNotes.Description = eTgnotes.WeightSpecs;
            tradingNotes.ItemId      = inventTable.ItemId;
            tradingNotes.PrintNotesInContract = NoYes::Yes;
            tradingNotes.insert();
        }

    }
}
